import json,sys,urllib.request,time,base64
K=sys.argv[1]; NEWCODE=base64.b64decode(sys.argv[2]).decode('utf-8')
B='https://irynakarmazina.app.n8n.cloud/api/v1/'
def GET(w):
    for a in range(8):
        try: return json.load(urllib.request.urlopen(urllib.request.Request(B+w,headers={'X-N8N-API-KEY':K}),timeout=15))
        except Exception: time.sleep(3)
    return None
def PUT(wid,d):
    payload={'name':d['name'],'nodes':d['nodes'],'connections':d['connections'],'settings':d.get('settings',{})}
    if d.get('staticData') is not None: payload['staticData']=d['staticData']
    body=json.dumps(payload).encode('utf-8')
    for a in range(4):
        try: r=urllib.request.urlopen(urllib.request.Request(B+'workflows/'+wid,data=body,method='PUT',headers={'X-N8N-API-KEY':K,'Content-Type':'application/json'}),timeout=45); return r.status
        except Exception: time.sleep(3)
    return None
def ACT(wid):
    try: urllib.request.urlopen(urllib.request.Request(B+'workflows/'+wid+'/activate',method='POST',headers={'X-N8N-API-KEY':K}),timeout=20)
    except Exception: pass

# 1) Maersk Розбір
d=GET('workflows/JQKA35haUsXU4XqE')
if d:
    open('/root/mk-backup-split.json','w').write(json.dumps(d))
    done=False
    for n in d['nodes']:
        if n.get('name')=='Розбір' and n.get('type')=='n8n-nodes-base.code':
            n['parameters']['jsCode']=NEWCODE; done=True
    print('Maersk Розбір patched:',done,'| PUT',PUT('JQKA35haUsXU4XqE',d)); ACT('JQKA35haUsXU4XqE')

# 2) кольори дашборд + вітрина
OLD="'Завантажений на авто/потяг'"
NEW="'Завантажений на авто/потяг','Завантажений на потяг','Завантажений на авто'"
for wid,label in [('1YdXnLFOXI85IsWv','дашборд'),('VGi9phda7zLZC9eD','вітрина')]:
    d=GET('workflows/'+wid)
    if not d: print(label,'GET fail'); continue
    patched=0
    for n in d['nodes']:
        if n.get('type')=='n8n-nodes-base.code':
            c=(n.get('parameters') or {}).get('jsCode','')
            if 'const purple=' in c and OLD in c and 'Завантажений на потяг' not in c:
                n['parameters']['jsCode']=c.replace(OLD,NEW,1); patched+=1
    print(label,'кольори patched:',patched,'| PUT',(PUT(wid,d) if patched else 'skip')); 
    if patched: ACT(wid)
print('готово')

PYEOF
